//! Regression guards distilled from the 2026-07 strapi incident: a yarn v1
//! monorepo was `scan --mode vendored`-wired, then `scan --mode hosted` was
//! layered ON TOP of the vendored lock, and the subsequent `npx yarn@2`
//! install crashed inside yarn's own `patch:` builtin compat entries
//! (`#builtin<compat/fsevents>` / `#builtin<compat/resolve>` — a yarn-2.4.3 +
//! Node 23+ `util.isDate` removal, NOT a socket edit). These tests freeze
//! the guarantees that made the incident diagnosable:
//!
//! 1. vendored wiring is byte-surgical: only the targeted block changes,
//!    sibling versions and the packages yarn builtin-patches (fsevents,
//!    resolve) stay byte-identical, no `patch:` protocol string is ever
//!    introduced, and the crate's own lockfile parser still reads the file;
//! 2. the rewritten block's `#<sha1>` fragment and `integrity` SRI match the
//!    actual vendored blob bytes (the chain the forensics verified 48/48);
//! 3. hosted-over-vendored layering records the vendored blocks as its
//!    `original`s (data-level reversibility) — and `vendor --revert` after
//!    that overlay is CURRENTLY drift-skipped and lossy (blob deleted, lock
//!    left hosted, exit success): pinned here so a future hosted `--revert`
//!    must contend with these semantics deliberately;
//! 4. yarn berry locks containing builtin `patch:` resolution entries pass
//!    through both the vendor backend and the hosted redirect rewriter with
//!    those entries byte-identical — even when the redirected package IS the
//!    builtin-patched one (only its plain `npm:` entry is rewritten; the
//!    `patch:` block is skipped with a warning) — and vendoring a
//!    builtin-patched package itself refuses fail-closed instead of
//!    corrupting the entry.
//!
//! Hermetic: every test builds its own tempdir project, patches from a local
//! `.socket/blobs/` store (`PatchSources::blobs_only`), and never touches
//! the network or process environment (no `#[serial]` needed).

use std::collections::{BTreeMap, HashMap};
use std::path::{Path, PathBuf};

use base64::Engine as _;
use sha1::Digest as _;

use crate::hash::git_sha256::compute_git_sha256_from_bytes;
use crate::manifest::schema::{PatchFileInfo, PatchRecord};
use crate::patch::apply::PatchSources;
use crate::patch::redirect::{rewrite_registry_redirect, DepOverride, Integrity};
use crate::patch::vendor::lock_inventory::{inventory_npm_lock, LockIntegrity};
use crate::patch::vendor::npm_flavor::NpmLockFlavor;
use crate::patch::vendor::yarn_berry_lock::{revert_yarn_berry, vendor_yarn_berry};
use crate::patch::vendor::yarn_classic_lock::{revert_yarn_classic, vendor_yarn_classic};
use crate::patch::vendor::{RevertOutcome, VendorEntry, VendorOutcome};
use crate::utils::uri::encode_uri_component;

/// Canonical-grammar patch uuid (the vendor path layer validates the shape
/// fail-closed, so fixtures must use the real grammar).
const UUID: &str = "9f6b2c4e-1d3a-4f6b-8c2d-7e5a9b1c3d5f";
const TOKEN: &str = "11111111-1111-1111-1111-111111111111";
const ORIG_INDEX: &[u8] = b"module.exports = () => 'orig';\n";
const PATCHED_INDEX: &[u8] = b"module.exports = () => 'patched';\n";

// ───────────────────────── classic (yarn v1) fixture ─────────────────────────

