/// Berry lock with the incident's exact coexistence shape: yarn's OWN
/// builtin `patch:` compat entries for fsevents and resolve (`yarn@2.4.3`
/// spells the fragment `#builtin<...>`, yarn 4 `#optional!builtin<...>` —
/// one of each below) alongside a plain npm: entry socket patches.
const BERRY_BEFORE_LOCK: &str = r#"# This file is generated by running "yarn install" inside your project.
# Manual changes might be lost - proceed with caution!

__metadata:
  version: 8
  cacheKey: 10c0

"berry-app@workspace:.":
  version: 0.0.0-use.local
  resolution: "berry-app@workspace:."
  dependencies:
    fsevents: "npm:2.3.2"
    left-pad: "npm:1.3.0"
    resolve: "npm:1.20.0"
  languageName: unknown
  linkType: soft

"fsevents@npm:2.3.2":
  version: 2.3.2
  resolution: "fsevents@npm:2.3.2"
  dependencies:
    node-gyp: "npm:latest"
  checksum: 10c0/aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa
  conditions: os=darwin
  languageName: node
  linkType: hard

"fsevents@patch:fsevents@npm%3A2.3.2#optional!builtin<compat/fsevents>":
  version: 2.3.2
  resolution: "fsevents@patch:fsevents@npm%3A2.3.2#optional!builtin<compat/fsevents>::version=2.3.2&hash=df0bf1"
  dependencies:
    node-gyp: "npm:latest"
  checksum: 10c0/bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb
  conditions: os=darwin
  languageName: node
  linkType: hard

"left-pad@npm:1.3.0":
  version: 1.3.0
  resolution: "left-pad@npm:1.3.0"
  checksum: 10c0/3fb59c76e281a2f5c810ad71dbbb8eba8b10c6cf94733dc7f27b8c516a5376cacea53543e76f6ae477d866c8954b27f1e15ca349424c2542474eb5bb1d2b6955
  languageName: node
  linkType: hard

"resolve@npm:1.20.0":
  version: 1.20.0
  resolution: "resolve@npm:1.20.0"
  dependencies:
    is-core-module: "npm:^2.2.0"
    path-parse: "npm:^1.0.6"
  checksum: 10c0/cccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccccc
  languageName: node
  linkType: hard

"resolve@patch:resolve@npm%3A1.20.0#builtin<compat/resolve>":
  version: 1.20.0
  resolution: "resolve@patch:resolve@npm%3A1.20.0#builtin<compat/resolve>::version=1.20.0&hash=c3c19d"
  dependencies:
    is-core-module: "npm:^2.2.0"
    path-parse: "npm:^1.0.6"
  checksum: 10c0/dddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddd
  languageName: node
  linkType: hard
"#;

/// serde_json-pretty shape (2-space, trailing newline) so the berry
/// backend's revert round-trips byte-exactly.
const BERRY_BEFORE_PKG: &str = r#"{
  "name": "berry-app",
  "version": "1.0.0",
  "packageManager": "yarn@4.12.0",
  "dependencies": {
    "fsevents": "2.3.2",
    "left-pad": "1.3.0",
    "resolve": "1.20.0"
  }
}
"#;

const BERRY_YARNRC: &str =
    "nodeLinker: node-modules\nenableGlobalCache: true\nenableTelemetry: false\n";

/// The two builtin patch: entries, verbatim — they must survive every socket
/// operation byte-identically.
const FSEVENTS_PATCH_ENTRY: &str = "\"fsevents@patch:fsevents@npm%3A2.3.2#optional!builtin<compat/fsevents>\":\n  version: 2.3.2\n  resolution: \"fsevents@patch:fsevents@npm%3A2.3.2#optional!builtin<compat/fsevents>::version=2.3.2&hash=df0bf1\"\n  dependencies:\n    node-gyp: \"npm:latest\"\n  checksum: 10c0/bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb\n  conditions: os=darwin\n  languageName: node\n  linkType: hard";
const RESOLVE_PATCH_ENTRY: &str = "\"resolve@patch:resolve@npm%3A1.20.0#builtin<compat/resolve>\":\n  version: 1.20.0\n  resolution: \"resolve@patch:resolve@npm%3A1.20.0#builtin<compat/resolve>::version=1.20.0&hash=c3c19d\"\n  dependencies:\n    is-core-module: \"npm:^2.2.0\"\n    path-parse: \"npm:^1.0.6\"\n  checksum: 10c0/dddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddddd\n  languageName: node\n  linkType: hard";

/// `patch:` occurrences in the pristine berry lock: 2 per builtin entry
/// (key + resolution) × 2 entries.
const BERRY_PATCH_COUNT: usize = 4;

struct BerryFx {
    tmp: tempfile::TempDir,
    record: PatchRecord,
}

impl BerryFx {
    fn root(&self) -> &Path {
        self.tmp.path()
    }

    fn lock_text(&self) -> String {
        std::fs::read_to_string(self.root().join("yarn.lock")).unwrap()
    }

    fn pkg_text(&self) -> String {
        std::fs::read_to_string(self.root().join("package.json")).unwrap()
    }

    async fn vendor(&self, name: &str, version: &str) -> VendorOutcome {
        let blobs = self.root().join(".socket/blobs");
        let sources = PatchSources::blobs_only(&blobs);
        let purl = format!("pkg:npm/{name}@{version}");
        vendor_yarn_berry(
            &purl,
            &self.root().join("node_modules").join(name),
            self.root(),
            &self.record,
            &sources,
            "2026-07-23T00:00:00Z",
            false,
            false,
            None,
        )
        .await
    }
}

/// Berry project with `installed_name` staged under node_modules/ (the
/// package a test will try to vendor).
fn berry_fx(installed_name: &str, installed_version: &str) -> BerryFx {
    let tmp = tempfile::tempdir().unwrap();
    let root = tmp.path();

    let installed = root.join("node_modules").join(installed_name);
    std::fs::create_dir_all(&installed).unwrap();
    std::fs::write(
        installed.join("package.json"),
        format!(r#"{{"name":"{installed_name}","version":"{installed_version}"}}"#),
    )
    .unwrap();
    std::fs::write(installed.join("index.js"), ORIG_INDEX).unwrap();

    let blobs = root.join(".socket/blobs");
    std::fs::create_dir_all(&blobs).unwrap();
    let after_hash = compute_git_sha256_from_bytes(PATCHED_INDEX);
    std::fs::write(blobs.join(&after_hash), PATCHED_INDEX).unwrap();

    std::fs::write(root.join("package.json"), BERRY_BEFORE_PKG).unwrap();
    std::fs::write(root.join("yarn.lock"), BERRY_BEFORE_LOCK).unwrap();
    std::fs::write(root.join(".yarnrc.yml"), BERRY_YARNRC).unwrap();

    BerryFx {
        tmp,
        record: record_for(&after_hash),
    }
}

// ───────────────────────────── berry tests ─────────────────────────────

/// Incident guard 4a: vendoring an unrelated package in a berry lock leaves
/// yarn's builtin `patch:` compat entries byte-identical (both the yarn-2
/// `#builtin<...>` and yarn-4 `#optional!builtin<...>` spellings), adds no
/// new `patch:` strings, and the whole edit reverts byte-exactly.
///
/// RED-verified: expecting BERRY_PATCH_COUNT+1 occurrences fails; tampering
/// a byte in FSEVENTS_PATCH_ENTRY's expectation fails the verbatim assert.
#[tokio::test]
async fn berry_vendor_leaves_builtin_patch_entries_byte_identical() {
    assert_eq!(
        BERRY_BEFORE_LOCK.matches("patch:").count(),
        BERRY_PATCH_COUNT,
        "fixture sanity"
    );

    let fx = berry_fx("left-pad", "1.3.0");
    let entry = expect_done(fx.vendor("left-pad", "1.3.0").await).expect("ledger entry");

    let text = fx.lock_text();
    // The two builtin entries survive verbatim, and the rewrite introduced
    // no new patch: protocol strings (the incident's failing entry family).
    assert!(
        text.contains(FSEVENTS_PATCH_ENTRY),
        "fsevents builtin patch entry must survive byte-identically:\n{text}"
    );
    assert!(
        text.contains(RESOLVE_PATCH_ENTRY),
        "resolve builtin patch entry must survive byte-identically:\n{text}"
    );
    assert_eq!(
        text.matches("patch:").count(),
        BERRY_PATCH_COUNT,
        "vendoring must neither add nor remove patch: strings"
    );

    // The target entry was rewired to the workspace-bound file: locator.
    assert!(
        text.contains(&format!(
            "\"left-pad@file:./.socket/vendor/npm/{UUID}/left-pad-1.3.0.tgz::locator=berry-app%40workspace%3A.\":"
        )),
        "left-pad rewired: {text}"
    );
    assert!(
        !text.contains("\"left-pad@npm:1.3.0\":"),
        "the old registry entry key is replaced"
    );

    // The crate's own berry parser still reads the file; the untouched npm:
    // entries survive, patch:/file:/workspace resolutions are skipped by
    // design.
    let (flavor, entries) = inventory_npm_lock(fx.root()).await.expect("parseable");
    assert_eq!(flavor, NpmLockFlavor::YarnBerry);
    let mut got: Vec<(String, String)> = entries
        .iter()
        .map(|e| (e.name.clone(), e.version.clone()))
        .collect();
    got.sort();
    assert_eq!(
        got,
        vec![
            ("fsevents".to_string(), "2.3.2".to_string()),
            ("resolve".to_string(), "1.20.0".to_string()),
        ]
    );

    // Byte-exact round-trip: revert restores lock AND manifest, builtin
    // entries included.
    let outcome = revert_yarn_berry(&entry, fx.root(), false).await;
    assert!(outcome.success, "{:?}", outcome.error);
    assert!(outcome.warnings.is_empty(), "{:?}", outcome.warnings);
    assert_eq!(fx.lock_text(), BERRY_BEFORE_LOCK, "lock round-trips");
    assert_eq!(fx.pkg_text(), BERRY_BEFORE_PKG, "package.json round-trips");
}

/// Incident guard 4b: vendoring a package that yarn ITSELF builtin-patches
/// (fsevents — its lock resolves the name through a `patch:` protocol entry
/// vendor cannot own) refuses fail-closed BEFORE any write, instead of
/// corrupting the builtin entry.
///
/// RED-verified: dropping the patch: block from the fixture flips the
/// outcome to Done, failing the Refused assert.
#[tokio::test]
async fn berry_vendoring_a_builtin_patched_package_refuses_fail_closed() {
    let fx = berry_fx("fsevents", "2.3.2");
    let outcome = fx.vendor("fsevents", "2.3.2").await;

    match outcome {
        VendorOutcome::Refused { code, detail } => {
            assert_eq!(code, "vendor_override_conflict", "{detail}");
            assert!(
                detail.contains("patch:"),
                "the refusal names the un-ownable protocol family: {detail}"
            );
        }
        VendorOutcome::Done { result, .. } => panic!(
            "vendoring a builtin-patched package must refuse (got Done, success={})",
            result.success
        ),
    }

    // Refuse-early contract: nothing written.
    assert_eq!(fx.lock_text(), BERRY_BEFORE_LOCK);
    assert_eq!(fx.pkg_text(), BERRY_BEFORE_PKG);
    assert!(!fx.root().join(".socket/vendor").exists());
}

/// Incident guard 4c: the hosted redirect rewriter on a berry lock rewrites
/// ONLY the targeted npm: entry (gaining yarn's own `::__archiveUrl=`
/// binding) and leaves the builtin patch: entries byte-identical.
///
/// RED-verified: asserting BERRY_PATCH_COUNT+1 fails; asserting the fsevents
/// entry gained an __archiveUrl fails.
#[tokio::test]
async fn berry_hosted_redirect_leaves_builtin_patch_entries_untouched() {
    let hosted_url = format!(
        "https://patch.socket.dev/patch/npm/left-pad/1.3.0/{TOKEN}/{UUID}/left-pad-1.3.0.tgz"
    );
    let dep = DepOverride {
        ecosystem: "npm".to_string(),
        name: "left-pad".to_string(),
        namespace: None,
        version: "1.3.0".to_string(),
        token: TOKEN.to_string(),
        patch_uuid: UUID.to_string(),
        artifact_url: hosted_url.clone(),
        berry_zip_url: None,
        registry_override: None,
        integrity: Integrity {
            yarn_berry10c0: Some(
                "10c0/eeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeeee".to_string(),
            ),
            ..Integrity::default()
        },
    };

    let mut files = BTreeMap::new();
    files.insert("yarn.lock".to_string(), BERRY_BEFORE_LOCK.to_string());
    files.insert(".yarnrc.yml".to_string(), BERRY_YARNRC.to_string());
    let result = rewrite_registry_redirect(&files, &[dep]);

    let text = result.files.get("yarn.lock").expect("yarn.lock rewritten");
    let berry_edits: Vec<_> = result
        .edits
        .iter()
        .filter(|e| e.kind == "redirect_yarn_berry_entry")
        .collect();
    assert_eq!(berry_edits.len(), 1, "{:?}", result.edits);
    assert_eq!(berry_edits[0].key.as_deref(), Some("left-pad@1.3.0"));

    // The target gained yarn's own archive binding…
    assert!(
        text.contains(&format!(
            "  resolution: \"left-pad@npm:1.3.0::__archiveUrl={}\"",
            encode_uri_component(&hosted_url)
        )),
        "target entry redirected: {text}"
    );
    // …and the builtin patch: entries are byte-identical, count unchanged.
    assert!(text.contains(FSEVENTS_PATCH_ENTRY), "{text}");
    assert!(text.contains(RESOLVE_PATCH_ENTRY), "{text}");
    assert_eq!(
        text.matches("patch:").count(),
        BERRY_PATCH_COUNT,
        "redirect must not introduce or remove patch: strings"
    );
    assert!(
        !text.contains("fsevents@npm:2.3.2::__archiveUrl"),
        "untargeted packages must not be redirected"
    );
    // left-pad has no builtin patch: entry, so the protocol gate (and every
    // other berry gate) must stay silent. (Non-berry rewriters may still
    // warn, e.g. the npm one about the absent package-lock.json.)
    assert!(
        !result
            .warnings
            .iter()
            .any(|w| w.code.starts_with("redirect_yarn_berry")),
        "{:?}",
        result.warnings
    );
}

/// Incident guard 4d: redirecting a package yarn ITSELF builtin-patches
/// (resolve — the fixture holds both the plain `resolve@npm:1.20.0` entry
/// and the builtin `resolve@patch:...#builtin<compat/resolve>` entry at the
/// same version) rewrites ONLY the npm: entry and leaves the builtin
/// `patch:` block byte-identical, warning about the block it refused to
/// touch. Without the protocol gate the rewriter spliced an
/// `npm:...::__archiveUrl=` resolution under the still-`patch:` key — a
/// corrupted key/resolution protocol mismatch in the incident's exact error
/// family, emitted as a silent second edit.
///
/// RED-verified: with the protocol gate removed from `rewrite_yarn_berry`,
/// TWO `resolve@1.20.0` edits are emitted and the RESOLVE_PATCH_ENTRY
/// verbatim assert fails (resolution rewritten under the patch: key).
#[tokio::test]
async fn berry_hosted_redirect_of_builtin_patched_package_skips_patch_entry() {
    let hosted_url = format!(
        "https://patch.socket.dev/patch/npm/resolve/1.20.0/{TOKEN}/{UUID}/resolve-1.20.0.tgz"
    );
    let dep = DepOverride {
        ecosystem: "npm".to_string(),
        name: "resolve".to_string(),
        namespace: None,
        version: "1.20.0".to_string(),
        token: TOKEN.to_string(),
        patch_uuid: UUID.to_string(),
        artifact_url: hosted_url.clone(),
        berry_zip_url: None,
        registry_override: None,
        integrity: Integrity {
            yarn_berry10c0: Some(format!("10c0/{}", "f".repeat(128))),
            ..Integrity::default()
        },
    };

    let mut files = BTreeMap::new();
    files.insert("yarn.lock".to_string(), BERRY_BEFORE_LOCK.to_string());
    files.insert(".yarnrc.yml".to_string(), BERRY_YARNRC.to_string());
    let result = rewrite_registry_redirect(&files, &[dep]);

    let text = result.files.get("yarn.lock").expect("yarn.lock rewritten");

    // Exactly ONE edit — the plain npm: entry. (The corruption shape was
    // two edits both keyed resolve@1.20.0, the second under the patch: key.)
    let berry_edits: Vec<_> = result
        .edits
        .iter()
        .filter(|e| e.kind == "redirect_yarn_berry_entry")
        .collect();
    assert_eq!(berry_edits.len(), 1, "{:?}", result.edits);
    assert_eq!(berry_edits[0].key.as_deref(), Some("resolve@1.20.0"));

    // The plain npm: entry gained yarn's archive binding…
    assert!(
        text.contains(&format!(
            "  resolution: \"resolve@npm:1.20.0::__archiveUrl={}\"",
            encode_uri_component(&hosted_url)
        )),
        "plain npm: entry redirected: {text}"
    );
    // …the builtin patch: entries survive byte-identically (key AND
    // resolution — the corruption kept the key but rewrote the resolution),
    // with the patch: count unchanged…
    assert!(text.contains(RESOLVE_PATCH_ENTRY), "{text}");
    assert!(text.contains(FSEVENTS_PATCH_ENTRY), "{text}");
    assert_eq!(
        text.matches("patch:").count(),
        BERRY_PATCH_COUNT,
        "redirect must not introduce or remove patch: strings"
    );
    // …and the skip is loud, naming the un-ownable entry.
    assert!(
        result.warnings.iter().any(|w| {
            w.code == "redirect_yarn_berry_unsupported_protocol"
                && w.detail.contains("builtin<compat/resolve>")
        }),
        "warning must name the skipped builtin patch: entry: {:?}",
        result.warnings
    );
}
